import{_ as a,o as s,c as r,a2 as t}from"./chunks/framework.D5wUhsuj.js";const o="/docs/assets/logs-browser.aQcARtTY.png",i="/docs/assets/logs-advanced-filters.vJSlTIDq.png",n="/docs/assets/logs-results.BIldza1Z.png",b=JSON.parse('{"title":"Observability","description":"","frontmatter":{},"headers":[],"relativePath":"platform/observability.md","filePath":"platform/observability.md","lastUpdated":1783546178000}'),l={name:"platform/observability.md"};function d(p,e,c,h,g,u){return s(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="observability" tabindex="-1">Observability <a class="header-anchor" href="#observability" aria-label="Permalink to &quot;Observability&quot;">​</a></h1><p>prokube collects workload logs and exposes operational views for debugging Labs, pipelines, model deployments, services, agents, and other workspace workloads.</p><p>Observability is part of the shared platform foundation. Use workload-specific pages first when they provide status, events, metrics, or logs directly. Use the shared views when you need to search across workloads or inspect retained logs.</p><h2 id="logs-browser" tabindex="-1">Logs Browser <a class="header-anchor" href="#logs-browser" aria-label="Permalink to &quot;Logs Browser&quot;">​</a></h2><p>Open <strong>Logs</strong> in the prokube UI to search application and container logs without opening Grafana or using <code>kubectl</code> for every query.</p><p>Basic workflow:</p><ol><li>Open <strong>Logs</strong> in the prokube UI.</li><li>Select the workspace you want to inspect.</li><li>Choose a time range.</li><li>Add filters when needed.</li><li>Click <strong>Search Logs</strong>.</li></ol><p>Access is scoped to the workspaces you can access.</p><p><img src="'+o+'" alt="Logs browser" loading="lazy"></p><h2 id="filter-logs" tabindex="-1">Filter Logs <a class="header-anchor" href="#filter-logs" aria-label="Permalink to &quot;Filter Logs&quot;">​</a></h2><p>Start with broad filters and narrow the query when needed:</p><ul><li><strong>Time range</strong>: select a preset such as the last 15 minutes, 1 hour, or 24 hours, or provide a custom range.</li><li><strong>Free text search</strong>: filter log messages that contain specific text.</li><li><strong>Log limit</strong>: choose how many entries to return. The UI caps requests to keep queries responsive.</li></ul><p>Use advanced filters for targeted debugging:</p><ul><li><strong>Pod name</strong>: filter by an exact pod name or a prefix pattern such as <code>training-job-*</code>.</li><li><strong>Container name</strong>: filter a specific container in a multi-container pod.</li><li><strong>Label filters</strong>: filter by Kubernetes labels discovered from the selected workspace.</li></ul><p><img src="'+i+'" alt="Logs advanced filters" loading="lazy"></p><h2 id="read-and-export-results" tabindex="-1">Read and Export Results <a class="header-anchor" href="#read-and-export-results" aria-label="Permalink to &quot;Read and Export Results&quot;">​</a></h2><p>After a search, the Logs page shows returned entries and a histogram for the selected time range. Use the histogram to spot bursts of activity and narrow the time window.</p><p>Use <strong>Download</strong> to save the shown log entries as a text file for sharing or offline analysis. Review downloaded logs before sharing them outside your team; application logs can contain user data, object paths, request payloads, or other sensitive values.</p><p><img src="'+n+'" alt="Logs results" loading="lazy"></p><h2 id="common-uses" tabindex="-1">Common Uses <a class="header-anchor" href="#common-uses" aria-label="Permalink to &quot;Common Uses&quot;">​</a></h2><ul><li><strong>Pipeline debugging</strong>: search for pods created by a pipeline run when a step fails or when no logs are shown in the pipeline details page.</li><li><strong>Lab debugging</strong>: search for the Lab pod when the environment fails to start or crashes after startup.</li><li><strong>Model-serving debugging</strong>: search by model pod name or labels to inspect startup, model loading, and request-handling logs.</li><li><strong>Application debugging</strong>: search logs for custom services deployed into your workspace.</li><li><strong>AgentOps debugging</strong>: search sandbox, MCP server, gateway, or agent runtime logs when the feature-specific page does not show enough detail.</li></ul><h2 id="metrics-and-dashboards" tabindex="-1">Metrics and Dashboards <a class="header-anchor" href="#metrics-and-dashboards" aria-label="Permalink to &quot;Metrics and Dashboards&quot;">​</a></h2><p>Metrics dashboards are exposed through workload pages where possible. Platform-wide dashboards are usually an administrator/operator workflow and are exposed through <a href="https://grafana.com/docs/grafana/latest/" target="_blank" rel="noreferrer">Grafana</a> when the deployment includes it.</p><p>Examples:</p><ul><li>model detail pages can link to model-serving metrics;</li><li>platform administrators use Grafana, <a href="https://prometheus.io/docs/introduction/overview/" target="_blank" rel="noreferrer">Prometheus</a>, and <a href="https://prometheus.io/docs/alerting/latest/alertmanager/" target="_blank" rel="noreferrer">Alertmanager</a> for service health, alerts, and capacity;</li><li>workload pages can surface events or conditions directly when Kubernetes already provides the relevant signal.</li></ul><p>Use metrics to understand rates, latency, resource pressure, and longer-term behavior. Use logs to inspect specific failures, startup output, stack traces, and request-level details.</p><p>When these tools are exposed by your deployment:</p><ul><li>use Grafana for curated dashboards and ad hoc exploration;</li><li>use Prometheus or Grafana Explore for metrics queries;</li><li>use Loki or Grafana Explore for log queries that need LogQL beyond the prokube Logs page.</li></ul><p>Broad Grafana or Loki access can expose logs and metrics across namespaces depending on the configured permissions. Treat platform dashboards as administrator-facing unless your administrator has documented the access scope for your user or group.</p><h2 id="kubernetes-events" tabindex="-1">Kubernetes Events <a class="header-anchor" href="#kubernetes-events" aria-label="Permalink to &quot;Kubernetes Events&quot;">​</a></h2><p>Logs do not replace Kubernetes events. Events are often the best first signal for scheduling failures, image pull errors, missing secrets, failed volume mounts, admission failures, and quota pressure.</p><p>Start with the workload detail page when available. For command-line debugging, see <a href="./kubernetes.html#debug-workloads">Kubernetes Resources</a>.</p><h2 id="retention-and-limits" tabindex="-1">Retention and Limits <a class="header-anchor" href="#retention-and-limits" aria-label="Permalink to &quot;Retention and Limits&quot;">​</a></h2><p>Log availability depends on platform retention settings. Older logs may no longer be available.</p><p>The Logs page searches application and container logs stored in Loki. It does not guarantee that every platform component, audit event, or Kubernetes event is available as a log entry.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./kubernetes.html">Kubernetes Resources</a></li><li><a href="./system_status.html">System Status</a></li><li><a href="./../labs/">Labs</a></li><li><a href="./../mlops/pipelines.html">Pipelines</a></li><li><a href="./../mlops/model_serving.html">Model Serving</a></li><li><a href="./../admin/">Admin Documentation</a></li></ul>',37)])])}const f=a(l,[["render",d]]);export{b as __pageData,f as default};
